const soln = (n, edges, energy, maxCapacity, start, destination) => {
    // Already at the destination
    if (start === destination) {
        return 0;
    }

    // Build unweighted directional graph
    const adjList = Array(n).fill().map(() => []);

    for (const [u, v] of edges) {
        adjList[u].push(v);
    }

    // The state is distance + current energy.
    // Imagine we have two paths that end at the same node.
    // From the 1st path, we can get 5 energy; from the 2nd one, only 2.
    // We will mark the node as visited once one of these paths reaches it.
    // To fix this concurrency issue, use a 2D state.
    const visited = new Set();

    const queue = [];

    queue.push([start, maxCapacity, 0]);

    while (queue.length) {
        const [u, uEnergy, dist] = queue.shift();

        for (const v of adjList[u]) {
            let vEnergy = uEnergy - 1;

            const state = `${v},${vEnergy}`;

            if (vEnergy < 0 || visited.has(state)) {
                continue;
            }

            visited.add(state);

            // We reached the destination
            if (v === destination) {
                return dist + 1;
            }

            if (energy[v]) {
                vEnergy = maxCapacity;
            }

            queue.push([v, vEnergy, dist + 1]);
        }
    }

    return -1;
};

