int getMinTime(vector<vector<int>> &graph, unordered_map<int,int> &eMap, int source, int energy, int target){
    queue<pair<int,int>> q;
    q.push({source,energy});

    int totalTime =0;
    int n = graph.size();
    vector<int>dist(n,0);
    int cou = 0;

    while(!q.empty()){
        int len =  q.size();
        while(len--){
            if(cou>maxIterations) return -1;
            cou++;
            pair<int,int> pii = q.front();
            int currNode = pii.first;
            int currEnergy = pii.second;
            q.pop();
            if(currNode==target) return totalTime;
            for(int i=0;i<graph[currNode].size();i++){
                int nextNode = graph[currNode][i];
                if(dist[nextNode]>(currEnergy+eMap[nextNode]-1)) continue;
                dist[nextNode] = currEnergy - 1 + eMap[nextNode];
                q.push({nextNode,dist[nextNode]});
            }
        }
        totalTime++;
    }
    return -1;
}
