Here's the C++ code that uses Dijkstra's Algorithm with the energy level as an additional state constraint. The algorithm computes the minimum time for the frog to reach the destination while managing its energy level.

using namespace std;

// Node structure in priority queue
struct NodeState {
    int node;
    int energy;
    int time;

    bool operator>(const NodeState& other) const {
        return time > other.time;
    }
};

int dijkstraWithEnergy(int n, vector<vector<pair<int, int>>>& graph, int source, int destination, int maxEnergy, vector<int>& energyDrinks) {
    // Priority queue for Dijkstra (min-heap), stores (time, node, remaining energy)
    priority_queue<NodeState, vector<NodeState>, greater<NodeState>> pq;
    // Distance table to store the minimum time to reach a node with a certain energy level
    vector<vector<int>> dist(n, vector<int>(maxEnergy + 1, INT_MAX));

    // Start at the source node with full energy
    pq.push({source, maxEnergy, 0});
    dist[source][maxEnergy] = 0;

    while (!pq.empty()) {
        auto [currentNode, currentEnergy, currentTime] = pq.top();
        pq.pop();

        // If we reached the destination, return the time
        if (currentNode == destination) {
            return currentTime;
        }

        // If there's an energy drink at this node, refill the energy to max
        if (energyDrinks[currentNode]) {
            currentEnergy = maxEnergy;
        }

        // Explore all neighbors
        for (auto& neighbor : graph[currentNode]) {
            int nextNode = neighbor.first;
            int nextEnergy = currentEnergy - 1;  // Energy decreases by 1 with each move
            int nextTime = currentTime + 1;

            // If energy is zero, we can't move further
            if (nextEnergy < 0) continue;

            // If we found a faster path to the neighbor with this energy level, push it to the queue
            if (nextTime < dist[nextNode][nextEnergy]) {
                dist[nextNode][nextEnergy] = nextTime;
                pq.push({nextNode, nextEnergy, nextTime});
            }
        }
    }

    // If the destination is unreachable, return -1
    return -1;
}

int main() {
    // Number of nodes
    int n = 5;

    // Graph representation: adjacency list (node -> list of {neighbor, weight})
    vector<vector<pair<int, int>>> graph(n);
